"""
PP000004 — Main body extruded from 20-point profile, chamfered top/bottom,
with sketch cuts, extrude profiles, and all 6 loft bodies fused.

Pipeline:
  1. Extrude 20-pt profile 150mm (-Z direction)
  2. Chamfer top (Z=75) and bottom (Z=-75) edges: 3mm inward / 6mm down
  3. Sketch cuts, extrude profiles, loft bodies 1-6
"""

from OCP.BRepBuilderAPI import (
    BRepBuilderAPI_MakePolygon,
    BRepBuilderAPI_MakeFace,
    BRepBuilderAPI_Transform,
)
from OCP.BRepPrimAPI import BRepPrimAPI_MakePrism
from OCP.BRepFilletAPI import BRepFilletAPI_MakeChamfer
from OCP.BRepOffsetAPI import BRepOffsetAPI_ThruSections
from OCP.BRepAlgoAPI import BRepAlgoAPI_Cut, BRepAlgoAPI_Fuse
from OCP.BRepAdaptor import BRepAdaptor_Surface
from OCP.BRepCheck import BRepCheck_Analyzer
from OCP.GeomAbs import GeomAbs_Plane
from OCP.TopExp import TopExp_Explorer
from OCP.TopAbs import TopAbs_EDGE, TopAbs_FACE
from OCP.TopoDS import TopoDS_Face, TopoDS_Edge
from OCP.gp import gp_Pnt, gp_Vec, gp_Trsf
import math
from ocp_vscode import show

# ── Helpers ───────────────────────────────────────────────────────────────────

def cast_face(shape):
    f = TopoDS_Face()
    f.TShape(shape.TShape()); f.Location(shape.Location()); f.Orientation(shape.Orientation())
    return f

def cast_edge(shape):
    e = TopoDS_Edge()
    e.TShape(shape.TShape()); e.Location(shape.Location()); e.Orientation(shape.Orientation())
    return e

def get_horizontal_faces_at_z(shape, z_level, tol=1e-3):
    faces = []
    exp = TopExp_Explorer(shape, TopAbs_FACE)
    while exp.More():
        f = cast_face(exp.Current())
        adaptor = BRepAdaptor_Surface(f)
        if adaptor.GetType() == GeomAbs_Plane:
            normal = adaptor.Plane().Axis().Direction()
            loc = adaptor.Plane().Location()
            if abs(abs(normal.Z()) - 1.0) < 0.01 and abs(loc.Z() - z_level) < tol:
                faces.append(f)
        exp.Next()
    return faces

def edges_of_faces(faces):
    pairs = []
    for f in faces:
        exp = TopExp_Explorer(f, TopAbs_EDGE)
        while exp.More():
            pairs.append((cast_edge(exp.Current()), f))
            exp.Next()
    return pairs

