# 1. MAIN BODY — 20-point profile extruded 150mm in -Z (Z=75 → Z=-75)
# ═══════════════════════════════════════════════════════════════════════════════

main_pts = [
    (-185.0, 150.0, 75.0), (-200.0, 135.0, 75.0), (-200.0, -135.0, 75.0),
    (-185.0, -150.0, 75.0), (-165.0, -150.0, 75.0), (-150.0, -135.0, 75.0),
    (-150.0,   0.0, 75.0), ( -90.0,   0.0, 75.0), ( -75.0,  15.0, 75.0),
    ( -75.0, 100.0, 75.0), (  75.0, 100.0, 75.0), (  75.0,  15.0, 75.0),
    (  90.0,   0.0, 75.0), ( 150.0,   0.0, 75.0), ( 150.0, -135.0, 75.0),
    ( 165.0, -150.0, 75.0), ( 185.0, -150.0, 75.0), ( 200.0, -135.0, 75.0),
    ( 200.0, 135.0, 75.0), ( 185.0, 150.0, 75.0),
]

poly = BRepBuilderAPI_MakePolygon()
for x, y, z in main_pts:
    poly.Add(gp_Pnt(x, y, z))
poly.Close()
face = BRepBuilderAPI_MakeFace(poly.Wire(), True).Face()
prism = BRepPrimAPI_MakePrism(face, gp_Vec(0, 0, -150))
prism.Build()
solid = prism.Shape()
print("Main body extruded: Z=75 → Z=-75")

# ═══════════════════════════════════════════════════════════════════════════════
# 2. CHAMFER — top (Z=75) and bottom (Z=-75), 3mm inward / 6mm down
# ═══════════════════════════════════════════════════════════════════════════════

top_pairs = edges_of_faces(get_horizontal_faces_at_z(solid, 75.0))
bot_pairs = edges_of_faces(get_horizontal_faces_at_z(solid, -75.0))

chamfer = BRepFilletAPI_MakeChamfer(solid)
for edge, ref_face in top_pairs + bot_pairs:
    chamfer.Add(3.0, 6.0, edge, ref_face)
chamfer.Build()
if not chamfer.IsDone():
    raise RuntimeError("Chamfer failed.")
result = chamfer.Shape()
print(f"Chamfer applied: {len(top_pairs)} top + {len(bot_pairs)} bottom edges.")


# ── Helpers for loft section ──────────────────────────────────────────────────

def make_wire(pts_3d):
    poly = BRepBuilderAPI_MakePolygon()
    for x, y, z in pts_3d:
        poly.Add(gp_Pnt(x, y, z))
    poly.Close()
    return poly.Wire()

def make_rect_wire(pts):
    return make_wire(pts)

def translate_z(shape, dz):
    trsf = gp_Trsf()
    trsf.SetTranslation(gp_Vec(0.0, 0.0, dz))
    return BRepBuilderAPI_Transform(shape, trsf, True).Shape()

def safe_fuse(body, tool, label):
    op = BRepAlgoAPI_Fuse(body, tool)
    op.Build()
    if not op.IsDone():
        raise RuntimeError(f"{label} fuse failed.")
    print(f"{label} fused.")
    return op.Shape()

def arc_length_resample_3d(pts, n):
    segs = [math.sqrt(sum((pts[i+1][k]-pts[i][k])**2 for k in range(3))) for i in range(len(pts)-1)]
    total = sum(segs)
    cumul = [0.0]
    for s in segs: cumul.append(cumul[-1]+s)
    result_pts = []
    for t in [total*i/(n-1) for i in range(n)]:
        for i in range(len(cumul)-1):
            if cumul[i] <= t <= cumul[i+1]:
                sl = cumul[i+1]-cumul[i]
                frac = (t-cumul[i])/sl if sl>1e-12 else 0.0
                result_pts.append(tuple(pts[i][k]+frac*(pts[i+1][k]-pts[i][k]) for k in range(3)))
                break
    return result_pts

def first_corner_index(pts, threshold=100.0):
    for i in range(1, len(pts)-1):
        ax=pts[i][0]-pts[i-1][0]; az=pts[i][2]-pts[i-1][2]
        bx=pts[i+1][0]-pts[i][0]; bz=pts[i+1][2]-pts[i][2]
        la=math.sqrt(ax**2+az**2); lb=math.sqrt(bx**2+bz**2)
        if la<1e-9 or lb<1e-9: continue
        cos_a=max(-1.,min(1.,(ax*bx+az*bz)/(la*lb)))
        if math.degrees(math.acos(cos_a))>threshold: return i
    return 0

