r2 = arc_length_resample_3d([(x, y, z + 5.0) for x, y, z in new_loft7_p2], N7)

lb_new7 = BRepOffsetAPI_ThruSections(True, True)
lb_new7.AddWire(make_rect_wire(r1))
lb_new7.AddWire(make_rect_wire(r2))
lb_new7.Build()
if not lb_new7.IsDone():
    lb_new7 = BRepOffsetAPI_ThruSections(True, False)
    lb_new7.AddWire(make_rect_wire(r1))
    lb_new7.AddWire(make_rect_wire(r2))
    lb_new7.Build()
if not lb_new7.IsDone(): raise RuntimeError("New loft 7 failed.")
op_new7 = BRepAlgoAPI_Cut(result, lb_new7.Shape())
op_new7.Build()
if not op_new7.IsDone(): raise RuntimeError("New loft 7 cut failed.")
result = op_new7.Shape()
print("LoftBodyNew7 cut applied.")

